class MinHeap {
    constructor() {
        this.heap = [];
    }

    offer(val) {
        this.heap.push(val);
        this.heap.sort((a, b) => a - b);
    }

    poll() {
        return this.heap.shift();
    }

    peek() {
        return this.heap[0];
    }

    size() {
        return this.heap.length;
    }
}
